#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,r,p,a[N],t[N<<2],tag[N<<2];
int dep[N],son[N],sz[N],top[N],dfn[N],w[N],num,f[N];
vector<int> e[N];

void dfs1(int x,int fa){
	f[x]=fa;
    dep[x]=dep[fa]+1;
    sz[x]=1;
    for(int y:e[x])
        if(y!=fa){
            dfs1(y,x);
            if(sz[y]>sz[son[x]])
                son[x]=y;
            sz[x]+=sz[y];
        }
}

void dfs2(int x,int fa,int topx){
    dfn[x]=++num;
    w[num]=x;
    top[x]=topx;
    if(son[x])
        dfs2(son[x],x,topx);
    for(int y:e[x])
        if(y!=fa && y!=son[x])
            dfs2(y,x,y);
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=a[w[l]]%p;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=(t[cur*2]+t[cur*2+1])%p;
}

void push_down(int cur,int l,int r){
    int mid=l+r>>1;
    if(tag[cur]){
        t[cur*2]=(t[cur*2]+1ll*(mid-l+1)*tag[cur])%p;
        tag[cur*2]=(tag[cur*2]+tag[cur])%p;
        t[cur*2+1]=(t[cur*2+1]+1ll*(r-mid)*tag[cur])%p;
        tag[cur*2+1]=(tag[cur*2+1]+tag[cur])%p;
        tag[cur]=0;
    }
}

void modify(int cur,int l,int r,int x,int y,int k){
    if(x<=l && r<=y){
        t[cur]=(t[cur]+1ll*(r-l+1)*k)%p;
        tag[cur]=(tag[cur]+k)%p;
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=(t[cur*2]+t[cur*2+1])%p;
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,res=0;
    push_down(cur,l,r);
    if(x<=mid)
        res=(res+query(cur*2,l,mid,x,y))%p;
    if(y>mid)
        res=(res+query(cur*2+1,mid+1,r,x,y))%p;
    return res;
}

void Add(int x,int y,int k){
	while(top[x]!=top[y]){
		if(dep[top[x]]<dep[top[y]])
			swap(x,y);
		modify(1,1,n,dfn[top[x]],dfn[x],k);
		x=f[top[x]];
	}
	if(dep[x]<dep[y])
		modify(1,1,n,dfn[x],dfn[y],k);
	else
		modify(1,1,n,dfn[y],dfn[x],k);
}

int Ask(int x,int y){
	int res=0;
	while(top[x]!=top[y]){
		if(dep[top[x]]<dep[top[y]])
			swap(x,y);
		res=(res+query(1,1,n,dfn[top[x]],dfn[x]))%p;
		x=f[top[x]];
	}
	if(dep[x]<dep[y]){
		res=(res+query(1,1,n,dfn[x],dfn[y]))%p;
		return res;
	}else{
		res=(res+query(1,1,n,dfn[y],dfn[x]))%p;
		return res;
	}
} 

int main(){
    scanf("%d%d%d%d",&n,&m,&r,&p);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    dfs1(r,0);
    dfs2(r,0,r);
    build(1,1,n);
    while(m--){
        int op,x,y,k;
        scanf("%d",&op);
        if(op==1){
            scanf("%d%d%d",&x,&y,&k);
            Add(x,y,k%p);
        }else if(op==2){
            scanf("%d%d",&x,&y);
            printf("%d\n",Ask(x,y));
        }else if(op==3){
            scanf("%d%d",&x,&k);
            modify(1,1,n,dfn[x],dfn[x]+sz[x]-1,k%p);
        }else{
            scanf("%d",&x);
            printf("%d\n",query(1,1,n,dfn[x],dfn[x]+sz[x]-1));
        }
    }
    return 0;
}
